     1→import { Router } from 'express';
     2→import { db } from '../db';
     3→import { readLocalUsers, writeLocalUsers } from '../localFallback';
     4→
     5→const router = Router();
     6→
     7→// Online threshold: 3 minutes (heartbeat every 60s, so 3 missed beats = offline)
     8→const ONLINE_THRESHOLD_MS = 3 * 60 * 1000;
     9→
    10→function deriveStatus(lastSeenAt: Date | null): 'online' | 'offline' {
    11→  if (!lastSeenAt) return 'offline';
    12→  return (Date.now() - lastSeenAt.getTime()) < ONLINE_THRESHOLD_MS ? 'online' : 'offline';
    13→}
    14→
    15→const MSK = 'Europe/Moscow';
    16→
    17→function toMskTime(date: Date): string {
    18→  return date.toLocaleTimeString('ru-RU', { hour: '2-digit', minute: '2-digit', timeZone: MSK });
    19→}
    20→
    21→function toMskDate(date: Date): string {
    22→  return date.toLocaleDateString('ru-RU', { day: 'numeric', month: 'short', timeZone: MSK });
    23→}
    24→
    25→function formatLastSeen(lastSeenAt: Date | null): string {
    26→  if (!lastSeenAt) return 'Не в сети';
    27→  const diffMs = Date.now() - lastSeenAt.getTime();
    28→  if (diffMs < 0) return 'Не в сети';
    29→  if (diffMs < ONLINE_THRESHOLD_MS) return 'В сети';
    30→  const diffMin = Math.floor(diffMs / 60_000);
    31→  if (diffMin < 60) return `${diffMin} мин назад`;
    32→  const diffH = Math.floor(diffMin / 60);
    33→  if (diffH < 24) return `был(а) в ${toMskTime(lastSeenAt)} МСК`;
    34→  const diffD = Math.floor(diffH / 24);
    35→  if (diffD === 1) return `вчера в ${toMskTime(lastSeenAt)} МСК`;
    36→  if (diffD < 7) return `${diffD} дня назад в ${toMskTime(lastSeenAt)} МСК`;
    37→  return `${toMskDate(lastSeenAt)} в ${toMskTime(lastSeenAt)} МСК`;
    38→}
    39→
    40→function mapRow(row: any) {
    41→  const lastSeenAt: Date | null = row.last_seen_at ? new Date(row.last_seen_at) : null;
    42→  const status = deriveStatus(lastSeenAt);
    43→  return {
    44→    name: row.name,
    45→    role: row.role,
    46→    pin: row.pin,
    47→    department: row.department,
    48→    bio: row.bio,
    49→    avatarColor: row.avatar_color,
    50→    status,
    51→    lastActive: formatLastSeen(lastSeenAt),
    52→  };
    53→}
    54→
    55→// GET /api/users
    56→router.get('/', async (_req, res) => {
    57→  if (db.pool && db.isConnected) {
    58→    try {
    59→      const result = await db.pool.query('SELECT * FROM marketing_users ORDER BY name ASC');
    60→      return res.json(result.rows.map(mapRow));
    61→    } catch (err: any) {
    62→      return res.status(500).json({ error: err.message });
    63→    }
    64→  }
    65→  res.json(readLocalUsers());
    66→});
    67→
    68→// POST /api/users  (create or upsert)
    69→router.post('/', async (req, res) => {
    70→  const { name, role, pin, department, bio, avatarColor } = req.body;
    71→  if (!name || !role || !pin) {
    72→    return res.status(400).json({ error: 'ФИО, роль и ПИН-код обязательны' });
    73→  }
    74→  const dept = department || (role === 'admin' ? 'Администрация' : 'Отдел продаж');
    75→  const color = avatarColor || 'from-indigo-500 to-purple-600';
    76→
    77→  if (db.pool && db.isConnected) {
    78→    try {
    79→      await db.pool.query(`
    80→        INSERT INTO marketing_users (name, role, pin, department, bio, avatar_color, status, last_active)
    81→        VALUES ($1, $2, $3, $4, $5, $6, 'offline', 'Не в сети')
    82→        ON CONFLICT (name) DO UPDATE SET
    83→          role = EXCLUDED.role, pin = EXCLUDED.pin, department = EXCLUDED.department,
    84→          bio = EXCLUDED.bio, avatar_color = EXCLUDED.avatar_color
    85→      `, [name, role, pin, dept, bio || '', color]);
    86→      return res.json({ success: true, name });
    87→    } catch (err: any) {
    88→      return res.status(500).json({ error: 'Database write error: ' + err.message });
    89→    }
    90→  }
    91→
    92→  const users = readLocalUsers();
    93→  const idx = users.findIndex((u: any) => u.name === name);
    94→  const user = { name, role, pin, department: dept, bio: bio || '', avatarColor: color, status: 'offline', lastActive: 'Не в сети' };
    95→  if (idx >= 0) users[idx] = { ...users[idx], ...user };
    96→  else users.push(user);
    97→  writeLocalUsers(users);
    98→  res.json({ success: true, name });
    99→});
   100→
   101→// DELETE /api/users/:name
