    setEditingUser(null);
    setForm(EMPTY_FORM);
    setError(''); setSuccess('');
    setFormOpen(true);
  };

  const openEdit = (user: StaffMember) => {
    setEditingUser(user);
    setForm({ originalName: user.name, name: user.name, role: user.role, pin: user.pin, department: user.department });
    setError(''); setSuccess('');
    setFormOpen(true);
  };

