    27→  if (diffMs < 0) return 'Не в сети';
    28→  if (diffMs < ONLINE_THRESHOLD_MS) return 'В сети';
    29→  const diffMin = Math.floor(diffMs / 60_000);
    30→  if (diffMin < 60) return `${diffMin} мин назад`;
    31→  const diffH = Math.floor(diffMin / 60);
    32→  if (diffH < 24) return `был(а) в ${toMskTime(lastSeenAt)} МСК`;
    33→  const diffD = Math.floor(diffH / 24);
    34→  if (diffD === 1) return `вчера в ${toMskTime(lastSeenAt)} МСК`;
