    SELECT COUNT(*) as total_pending FROM leads_reporting
    WHERE booking_date < CURRENT_DATE
      AND status IN ('booked','rescheduled')
  \`);
  console.log('=== total pending (past, unresolved) ===', r2.rows[0]);

  // Test yclients match by phone (last 10 digits) + date
  const r3 = await pool.query(\`
    SELECT 
      lr.id, lr.client_name, lr.client_phone, lr.booking_date, lr.status,
      lr.amocrm_lead_id,
